import{c as t,Q as a,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse('{"title":"TheSequence — 2026-04-30","description":"","frontmatter":{"title":"TheSequence — 2026-04-30","date":"2026-04-30T00:00:00.000Z","source":"TheSequence","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-30-thesequence.md","filePath":"research/ai-news/2026-04/2026-04-30-thesequence.md","lastUpdated":1779894392000}'),r={name:"research/ai-news/2026-04/2026-04-30-thesequence.md"};function o(i,e,c,h,u,l){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="🔢-thesequence-—-2026-04-30" tabindex="-1">🔢 TheSequence — 2026-04-30 <a class="header-anchor" href="#🔢-thesequence-—-2026-04-30" aria-label="Permalink to &quot;🔢 TheSequence — 2026-04-30&quot;">​</a></h1><blockquote><p>165k+ 訂閱；ML / 企業 AI 應用週報，Jesus Rodriguez 主筆 來源：<a href="https://thesequence.substack.com/feed" target="_blank" rel="noreferrer">TheSequence</a></p></blockquote><hr><h2 id="the-sequence-opinion-852-the-bitter-lessons-for-agentic-interfaces-a-cli-for-everything" tabindex="-1"><a href="https://thesequence.substack.com/p/the-sequence-opinion-852-the-bitter" target="_blank" rel="noreferrer">The Sequence Opinion #852: The Bitter Lessons for Agentic Interfaces: A CLI for EVERYTHING</a> <a class="header-anchor" href="#the-sequence-opinion-852-the-bitter-lessons-for-agentic-interfaces-a-cli-for-everything" aria-label="Permalink to &quot;[The Sequence Opinion #852: The Bitter Lessons for Agentic Interfaces: A CLI for EVERYTHING](https://thesequence.substack.com/p/the-sequence-opinion-852-the-bitter)&quot;">​</a></h2><p><em>🔢 TheSequence | 2026-04-30</em></p><p>The next evolution of agentic SaaS isn’t more tool infrastructure. It’s a terminal.</p><p>I’ve been thinking a lot lately about why building agentic systems still feels so weirdly clunky, and I think I’ve finally put my finger on it.</p><p>Here’s the pattern that keeps repeating. You have an LLM. The LLM is, by any reasonable measure, the most capable text-processing machine ever built. It has read, in some statistical sense, every man page that exists, every Stack Overflow answer about awk, every dotfile checked into GitHub, every grumpy 2009 blog post about why your sed substitution didn’t work. It can produce a find ... -exec incantation that would make a 1990s sysadmin weep with nostalgia. It is, in a very deep sense, fluent in shell.</p><p>And then we sit it down in front of our shiny new SaaS platform and say: okay, we’re going to teach you how to use our product. Here are forty-seven carefully scoped MCP tools we wrote for you. Here is a JSON schema for each one. Here is a 200-page integration guide. Please do not improvise.</p><p>This is, I think, exactly backwards.</p><p>The thesis I want to argue is simple: the next phase of agentic SaaS is not about chat interfaces, and it’s not about ever-more-elaborate tool infrastructures. It’s about giving the agent a complete CLI and getting out of the way. Every SaaS, eventually, will ship a parallel command-line surface — not as a developer convenience, but as the primary interface for its non-human users. Which, increasingly, is most of its users.</p><p>The bitter lesson, applied to interfaces</p><p><a href="https://thesequence.substack.com/p/the-sequence-opinion-852-the-bitter" target="_blank" rel="noreferrer"> Read more </a></p><hr>',14)])])}const d=t(r,[["render",o]]);export{f as __pageData,d as default};
